1	interface QuoteStep {
2	  op: "quote";
3	  items: { type: string }[];
4	}
5	
6	interface Scenario {
7	  customer: { yearsWithMHPCO: number };
8	  steps: QuoteStep[];
9	}
10	
11	const BASE_PREMIUM: Record<string, number> = {
12	  sword: 100,
13	  amulet: 60,
14	  staff: 80,
15	  potion: 40,
16	  rune: 25,
17	  moonstone: 25,
18	};
19	
20	const FIRST_INSURANCE_RATE = 0.1;
21	const PROCESSING_FEE = 5;
22	
23	const RUNE_BLOCK_SIZE = 3;
24	const RUNE_BLOCK_PREMIUM = 60;
25	
26	const runesBasePremium = (runeCount: number): number =>
27	  runeCount === RUNE_BLOCK_SIZE ? RUNE_BLOCK_PREMIUM : runeCount * BASE_PREMIUM.rune;
28	
29	const policyBasePremium = (items: { type: string }[]): number => {
30	  const runeCount = items.filter((item) => item.type === "rune").length;
31	  const nonRuneBase = items
32	    .filter((item) => item.type !== "rune")
33	    .reduce((sum, item) => sum + BASE_PREMIUM[item.type], 0);
34	  return runesBasePremium(runeCount) + nonRuneBase;
35	};
36	
37	const quotePremium = (step: QuoteStep): number => {
38	  const policyBase = policyBasePremium(step.items);
39	  const firstInsurance = policyBase * FIRST_INSURANCE_RATE;
40	  return Math.ceil(policyBase + firstInsurance + PROCESSING_FEE);
41	};
42	
43	export const runScenario = (scenario: Scenario): { results: { premium: number }[] } => {
44	  return {
45	    results: scenario.steps.map((step) => ({ premium: quotePremium(step) })),
46	  };
47	};
